---@class BadgeChapterInfo
local BadgeChapterInfo = LxClass("BadgeChapterInfo",nil)
function BadgeChapterInfo:Initialize()
    --章节id
    self.chapterId = 0
    --章节星星数
    self.starNum = 0
    ---@type table 已领取星数宝箱状态
    self.starChest = {}
    ---@type table<number,number> 通关但未满星关卡-<关卡id，星星数>
    self.notFullStarBarriers = {}
end

function BadgeChapterInfo:SetData(pb)
    self.chapterId = pb.chapterId
    self.starNum = pb.starNum
    self.starChest = {}
    for key, value in ipairs(pb.starChest or {}) do
        self.starChest[value] = value
    end
    self.notFullStarBarriers = {}
    for _, barrier in ipairs(pb.notFullStarBarriers or {}) do
        self.notFullStarBarriers[barrier.barrierId] = barrier.star
    end
end

function BadgeChapterInfo:GetBoxState(index)--未达成 可领取 已领取 = 1,2,3
    local curStar = self.starNum or 0
    local starRef =  LxDataHelper.ParseNumber_Sign(GameTable.BadgeGameConfigRef.boxStar)
    local needStar = starRef[index]
    if curStar < needStar then return 1 end
    return self.starChest[index] and 3 or 2
end

function BadgeChapterInfo:GetChapterRed()
    local boxRef = LxDataHelper.ParseNumber_Sign(GameTable.BadgeGameConfigRef.boxStar)
    for indx, value in ipairs(boxRef) do
        if self:GetBoxState(indx)==2 then return true end
    end
    return false
end

function BadgeChapterInfo:PrioritySelBarrier()--优先选中关卡
    local chapterId = self.chapterId
    local curChapter = self:GetCorrespondingChapterId()
    local barrierRef = gModelBadgeGame:GetChapterBarrierRef(chapterId)
    if curChapter < chapterId then
        --章节未开启
        return barrierRef[1].refId
    elseif curChapter > chapterId then
        --章节已通关-有未满星关卡返回，否则最后1关
        for barrierId, barrierStar in pairs(self.notFullStarBarriers or {}) do
            return barrierId --if barrierId and barrierStar<=2 then return barrierId end
        end
        return barrierRef[#barrierRef].refId
    else
        --当前章节-返回下1关否则最后1关
        local barrierId = self:GetCorrespondingBarrierId()
        if barrierId <= 0 then
            return barrierRef[1].refId
        end
        local curBarrierRef = GameTable.BadgeGameBarrierRef[barrierId]
        if curBarrierRef and curBarrierRef.nextBarrier>0 then
            return curBarrierRef.nextBarrier
        else
            --下关属于新章节
            for tbarrierId, barrierStar in pairs(self.notFullStarBarriers or {}) do
                return tbarrierId --if barrierId and barrierStar<=2 then return barrierId end
            end
            return barrierRef[#barrierRef].refId
        end
    end
end

function BadgeChapterInfo:GetBarrierStar(barrierId,isArr)
    local total = 0
    local stars = {0,0,0}
    local tbarrierId = self:GetCorrespondingBarrierId()
    if tbarrierId < barrierId then
        return isArr and stars or total
    end  --未开启
    for id, star in pairs(self.notFullStarBarriers or {}) do--通关但未满星关卡
        if id == barrierId then
            for i ,num in ipairs(star or {}) do
                total = total+num
                stars[i] = num
            end
            return isArr and stars or total
        end
    end
    stars = {1,1,1}
    total = 3
    if tbarrierId >= barrierId then
        return isArr and stars or total
    end --满星通关
end

--未全部通关章节，未解锁章节，未完美通关(未满星)，已完美通关=1、2、3、4
function BadgeChapterInfo:GetChapterState()
    local curChapter = self:GetCorrespondingChapterId()
    if self.chapterId < curChapter then--通过章节
        if self:IsNotFullBarrier() then
            return 3
        else
            return 4
        end
    else
        if self.chapterId == curChapter then --当前章节
            local barrierRef = gModelBadgeGame:GetChapterBarrierRef(self.chapterId)
            local barrierId = self:GetCorrespondingBarrierId()
            if barrierId >= barrierRef[#barrierRef].refId then--通关章节
                if self:IsNotFullBarrier() then--存在没完美通关
                    return 3
                else
                    return 4
                end
            else--未全部通关章节
                return  1--gModelBadgeGame.barrierId==0 and 2 or
            end
        else--未开启章节
            if curChapter + 1 == self.chapterId then--前章节是否通关解锁新章节
                local barrierRef = gModelBadgeGame:GetChapterBarrierRef(curChapter)
                local chapterRef= GameTable.BadgeGameChapRef[self.chapterId]
                local curLv = gModelPlayer:GetPlayerLv()
                local chapterInfo = gModelBadgeGame:GetChapterById(curChapter)
                local pStar = (chapterRef.needStar==0 or chapterInfo.starNum>= chapterRef.needStar)
                local barrierId = self:GetCorrespondingBarrierId()
                if barrierId >= barrierRef[#barrierRef].refId and chapterRef.needLevel <= curLv and pStar then
                    return 1
                else
                    return 2
                end
            else
                return 2
            end
        end
    end
end

function BadgeChapterInfo:IsNotFullBarrier()--存在没完美通关
    local curChapter = self:GetCorrespondingChapterId()
    if curChapter < self.chapterId then return true end
    for _, value in pairs(self.notFullStarBarriers or {}) do
        return true
    end
    return false
end

function BadgeChapterInfo:PerfectPassedBarrier(barrierId)
    if self:GetCorrespondingBarrierId() < barrierId then return false end
    local curChapter = self:GetCorrespondingChapterId()
    if curChapter >= self.chapterId then
        for key, value in pairs(self.notFullStarBarriers or {}) do
            if key == barrierId then
                return false
            end
        end
        return true
    else
        return false
    end
end

--- 模块对应章节id
function BadgeChapterInfo:GetCorrespondingChapterId()
    local chapterType = self:GetInfoChapterType()
    if chapterType == ModelBadgeGame.CHAPTER_NORMAL then
        return gModelBadgeGame:GetNormalChapterId()
    else
        return gModelBadgeGame:GetNightmareChapterId()
    end
end

--- 模块对应关卡id
function BadgeChapterInfo:GetCorrespondingBarrierId()
    local chapterType = self:GetInfoChapterType()
    if chapterType == ModelBadgeGame.CHAPTER_NORMAL then
        return gModelBadgeGame:GetNormalBarrierId()
    else
        return gModelBadgeGame:GetNightmareBarrierId()
    end
end

function BadgeChapterInfo:GetInfoChapterType()
    return gModelBadgeGame:GetBadgeGameChapRefType(self.chapterId)
end
