function ModelBadgeGame:SetBadgeInfo(pd)
    self.chapterId = pd.chapterId
    self.barrierId = pd.barrierId
    self.yesterdayStar = pd.yesterdayStar
    self.dailyRewardState = pd.dailyRewardState

    for _, cInfo in ipairs(pd.chapterInfos or {}) do
        self:SetChapterInfo(cInfo)
    end

    for _, chapterId in ipairs(pd.unlockIdList or {}) do
        self.unlockIdList[chapterId] = chapterId
    end

    self.nightmareChapterId = pd.nightmareChapterId
    self.nightmareBarrierId = pd.nightmareBarrierId
end

function ModelBadgeGame:GetChapterById(chapterId)
    if not chapterId then return end
    return self.chapterInfos[chapterId]
end

function ModelBadgeGame:SetChapterInfo(pb)
    local chapterInfo = self:GetChapterById(pb.chapterId)
    if not chapterInfo then
        chapterInfo = BadgeChapterInfo:New()
        self.chapterInfos[pb.chapterId] = chapterInfo
    end
    chapterInfo:SetData(pb)
end

function ModelBadgeGame:SetBattleStarInfo(pb)
    self.starCondRefId = {}
    for _, value in ipairs(pb.starCondRefId or {}) do
        self.starCondRefId[value] = value
    end
end

function ModelBadgeGame:GetVideoList(barrier)
    return self.videoList[barrier]
end
function ModelBadgeGame:SetVideoInfo(pd)
    local videoDatas = self.videoList[pd.barrier]
    if videoDatas then
        local func = function(videoInfo,pd)
            if not videoInfo then
                return self:CreateBadgeGameVideoInfo(pd)
            end
            local roleInfo = videoInfo.roleInfo
            roleInfo:CreateByPb(pd.roleInfo)
            videoInfo.power = pd.power -- 阵容战力
            videoInfo.heroes = pd.heroes -- 上阵英雄refid
            videoInfo.isNull = tonumber(roleInfo.playerId) ~= 0 and true or nil
            videoInfo.reportUrl = pd.reportUrl
            videoInfo.time = pd.time
            return videoInfo
        end
        local earliest = videoDatas[1]
        videoDatas[1] = func(earliest,pd.earliestVideo)
        earliest = videoDatas[2]
        videoDatas[2] = func(earliest,pd.lowestPowerVideo)
        earliest = videoDatas[3]
        videoDatas[3] = func(earliest,pd.latestVideo)
    else
        local levelVideos = {}
        self.videoList[pd.barrier] = levelVideos
        levelVideos[1] =  self:CreateBadgeGameVideoInfo(pd.earliestVideo)
        levelVideos[2] = self:CreateBadgeGameVideoInfo(pd.lowestPowerVideo)
        levelVideos[3] = self:CreateBadgeGameVideoInfo(pd.latestVideo)
    end
end
function ModelBadgeGame:CreateBadgeGameVideoInfo(videoInfo)
    local roleInfo = StructSimplePlayerInfo:New()
    roleInfo:CreateByPb(videoInfo.roleInfo)
    local power = videoInfo.power -- 阵容战力
    local heroes = videoInfo.heroes -- 上阵英雄refid
    local isNull = tonumber(roleInfo.playerId) ~= 0 and true or nil
    local earliest = {
        roleInfo = roleInfo,
        power = power,
        heroes = heroes,
        isNull = isNull,
        reportUrl = videoInfo.reportUrl,
        time = videoInfo.time
    }
    return earliest
end
-- 数据接口

function ModelBadgeGame:GetChapterBarrierRef(chapterId)
    if not self.chapterBarrierRef then
        local refs = GameTable.BadgeGameBarrierRef
        local chapterBarrierRef = {}
        local ref_chapterId
        for key, value in pairs(refs) do
            ref_chapterId = value.chapterId
            local chapterBarrierRefs = chapterBarrierRef[ref_chapterId]
            if not chapterBarrierRefs then
                chapterBarrierRefs = {}
                chapterBarrierRef[ref_chapterId] = chapterBarrierRefs
            end
            table.insert(chapterBarrierRefs,value)
        end
        for type,typeRefs in pairs(chapterBarrierRef) do
            table.sort(typeRefs,function(a,b) return a.refId < b.refId end)
        end
        self.chapterBarrierRef = chapterBarrierRef
    end
    return self.chapterBarrierRef[chapterId]
end

function ModelBadgeGame:GetBadgeGameRed(chapterType)
    local chapterRef = GameTable.BadgeGameChapRef
    local chapterinfo = nil
    for _, value in pairs(chapterRef) do
        if chapterType == value.type then
            chapterinfo = self:GetChapterById(value.refId)
            if chapterinfo and chapterinfo:GetChapterRed() then
                return true
            end
        end
    end
    return false
end

function ModelBadgeGame:CheckIsOpenNightmare()
    return gModelFunctionOpen:CheckIsOpened(32000003)
end

function ModelBadgeGame:GetBadgeGameChapType(type)
    local badgeGameChapMap = self._badgeGameChapMap
    if not badgeGameChapMap then
        badgeGameChapMap = {}
        self._badgeGameChapMap = badgeGameChapMap
    end
    local badgeGameChapRefMap = badgeGameChapMap[type]
    if not badgeGameChapRefMap then
        badgeGameChapRefMap = {}
        for k,v in pairs(GameTable.BadgeGameChapRef) do
            if v.type == type then
                badgeGameChapRefMap[k] = v
            end
        end
        badgeGameChapMap[type] = badgeGameChapRefMap
    end
    return badgeGameChapRefMap
end

function ModelBadgeGame:GetBadgeGameChapRefByInfo(type,refId)
    local badgeGameChapRefMap = self:GetBadgeGameChapType(type)
    if not badgeGameChapRefMap then return end
    return badgeGameChapRefMap[refId]
end

function ModelBadgeGame:GetBadgeGameChapRefType(refId)
    local ref = GameTable.BadgeGameChapRef[refId]
    return ref and ref.type or ModelBadgeGame.CHAPTER_NORMAL
end

